import java.util.*;
public class PaymentProcessor {
    void process(int[] amounts, int target) {
        Arrays.sort(amounts);                          // O(n log n) — TimSort
        Map<Integer,Integer> freq = new HashMap<>();   // O(1) — declaration only
        for (int a : amounts) {                        // O(n) — loop over all amounts
            freq.put(a, freq.getOrDefault(a,0)+1);    // O(1) avg — HashMap put/get
        }                                              // Loop total: O(n)
        int lo=0, hi=amounts.length-1;                // O(1) — variable assignment
        while (lo < hi) {                             // O(n) iterations max (lo+hi meet)
            int sum = amounts[lo] + amounts[hi];       // O(1) — array index + add
            if (sum == target) { lo++; hi--; }        // O(1) — comparison + decrement
            else if (sum < target) lo++;               // O(1)
            else hi--;                                  // O(1)
        }                                              // While total: O(n)
        // OVERALL: O(n log n) [sort] + O(n) [freq] + O(n) [two pointers]
        //        = O(n log n) — dominated by sort
    }
    public static void main(String[] a){System.out.println("annotated");}
}

