public class FibonacciAnalysis {
    static int callCount = 0;

    // O(2ⁿ): exponential — recalculates same values repeatedly
    static long fib(int n) {
        callCount++;
        if (n <= 1) return n;
        return fib(n-1) + fib(n-2);
    }

    // O(n): memoization — each subproblem solved once
    static long fibMemo(int n, long[] memo) {
        if (n <= 1) return n;
        if (memo[n] != 0) return memo[n];
        memo[n] = fibMemo(n-1, memo) + fibMemo(n-2, memo);
        return memo[n];
    }

    public static void main(String[] args) {
        System.out.println("=== Naive Fibonacci call count vs 2ⁿ ===");
        for (int n : new int[]{10, 20, 30}) {
            callCount = 0;
            fib(n);
            System.out.printf("fib(%d): calls=%d, 2^%d=%d%n",
                n, callCount, n, (long)Math.pow(2, n));
        }
        System.out.println();
        System.out.println("=== Memoized Fibonacci ===");
        for (int n : new int[]{10, 20, 30, 50}) {
            long result = fibMemo(n, new long[n+1]);
            System.out.println("fibMemo(" + n + ") = " + result + " in O(n) calls");
        }
        System.out.println();
        System.out.println("Naive O(2ⁿ): fib(50) would need ~10^15 calls — impossible!");
        System.out.println("Memo  O(n):  fib(50) needs exactly 49 unique subproblems");
    }
}

