import java.util.*;
public class TradePipeline {
    static int kthLargest; // result from pipeline

    static int[] process(int[] trades, int k) {
        // Step 1: sort — O(n log n)
        int[] sorted = trades.clone();
        Arrays.sort(sorted);
        System.out.println("Step 1 - Sort: O(n log n)");

        // Step 2: deduplicate — O(n)
        Set<Integer> seen = new LinkedHashSet<>();
        for (int t : sorted) seen.add(t);
        int[] deduped = seen.stream().mapToInt(Integer::intValue).toArray();
        System.out.println("Step 2 - Deduplicate: O(n)");

        // Step 3: kth largest — O(1) — array is sorted, index directly
        kthLargest = deduped[deduped.length - k]; // sorted ascending, kth largest is from end
        System.out.println("Step 3 - kth largest: O(1) — direct index on sorted array");
        System.out.println("Overall pipeline: O(n log n) + O(n) + O(1) = O(n log n)");
        return deduped;
    }

    public static void main(String[] args) {
        int[] trades = {5000, 2000, 8000, 2000, 3000, 8000, 1000};
        System.out.println("Input: " + Arrays.toString(trades));
        System.out.println();
        int[] result = process(trades, 2); // 2nd largest
        System.out.println();
        System.out.println("Deduped sorted: " + Arrays.toString(result));
        System.out.println("2nd largest: " + kthLargest); // 5000
    }
}

