import java.util.*;
public class PairSum {
    // O(n²): try every pair
    static boolean bruteForce(int[] arr, int target) {
        for (int i=0; i<arr.length; i++)
            for (int j=i+1; j<arr.length; j++)
                if (arr[i]+arr[j]==target) return true;
        return false;
    }

    // O(n log n): sort, then two pointers
    static boolean sortedTwoPointers(int[] arr, int target) {
        int[] s = arr.clone();
        Arrays.sort(s); // O(n log n)
        int lo=0, hi=s.length-1;
        while (lo<hi) { // O(n)
            int sum=s[lo]+s[hi];
            if (sum==target) return true;
            else if (sum<target) lo++;
            else hi--;
        }
        return false;
        // Total: O(n log n) + O(n) = O(n log n)
    }

    // O(n): HashSet
    static boolean hashSetApproach(int[] arr, int target) {
        Set<Integer> seen = new HashSet<>();
        for (int x : arr) {
            if (seen.contains(target-x)) return true;
            seen.add(x);
        }
        return false;
        // O(n) — one pass, O(1) per HashSet operation
    }

    public static void main(String[] args) {
        int[] arr = {2, 7, 11, 15};
        int target = 9;
        System.out.println("Brute Force O(n²): " + bruteForce(arr, target));
        System.out.println("Two Pointers O(n log n): " + sortedTwoPointers(arr, target));
        System.out.println("HashSet O(n): " + hashSetApproach(arr, target));
        System.out.println("All agree: " + (bruteForce(arr,target)==hashSetApproach(arr,target)));
        System.out.println();
        System.out.println("Best choice: HashSet O(n) — optimal time and O(n) space");
        System.out.println("If space constrained: Two Pointers O(n log n) — O(1) extra space");
    }
}

