public class PowerFunction {
    static int callCount = 0;

    // O(n): multiply base n times
    static long naivePower(long base, int exp) {
        long result = 1;
        for (int i = 0; i < exp; i++) result *= base;
        return result;
    }

    // O(log n): divide exponent in half each time
    static long fastPower(long base, int exp) {
        callCount++;
        if (exp == 0) return 1;
        if (exp == 1) return base;
        if (exp % 2 == 0) {
            long half = fastPower(base, exp / 2); // ONE recursive call
            return half * half; // use result twice (not two calls!)
        } else {
            return base * fastPower(base, exp - 1); // odd: reduce by 1
        }
    }

    public static void main(String[] args) {
        System.out.println("=== Power Function Complexity ===");
        System.out.println("Naive O(n): 2^10 = " + naivePower(2, 10) + " (10 multiplications)");

        callCount = 0;
        long result = fastPower(2, 64);
        System.out.println("Fast O(log n): 2^64 = " + result);
        System.out.println("  Recursive calls: " + callCount + " (log₂(64)=6 levels)");

        System.out.println();
        System.out.println("Recursion tree for fastPower(2, 8):");
        System.out.println("  fastPower(2,8)");
        System.out.println("    └─ fastPower(2,4)");
        System.out.println("         └─ fastPower(2,2)");
        System.out.println("              └─ fastPower(2,1) = 2");
        System.out.println("  Each level: exponent halved → depth = log₂(8) = 3");
        System.out.println("  Total: O(log n) calls");

        System.out.println();
        System.out.println("Math.pow(): implemented in native code, typically O(log n) via fast power");

        // Verify
        System.out.println();
        System.out.println("Verification: naive==fast for 2^20: " +
            (naivePower(2,20)==fastPower(2,20)));
    }
}

