import java.util.*;
public class FixNSquared {
    record Trade(String trader, String stock) {}

    // O(n³) actually! nested O(n²) + result.contains O(n) inside = O(n³)
    static List<String> slowFind(List<Trade> trades) {
        List<String> result = new ArrayList<>();
        for (Trade t1 : trades)
            for (Trade t2 : trades)
                if (t1.trader.equals(t2.trader) && t1.stock.equals("RELIANCE") && t2.stock.equals("TCS"))
                    if (!result.contains(t1.trader)) result.add(t1.trader); // O(n) here!
        return result;
    }

    // O(n): one pass, HashSet per trader
    static List<String> fastFind(List<Trade> trades) {
        // Build: trader → set of stocks traded (O(n))
        Map<String, Set<String>> traderStocks = new HashMap<>();
        for (Trade t : trades)
            traderStocks.computeIfAbsent(t.trader(), k -> new HashSet<>()).add(t.stock());
        // Filter traders who have both RELIANCE and TCS (O(unique traders))
        List<String> result = new ArrayList<>();
        for (var entry : traderStocks.entrySet())
            if (entry.getValue().contains("RELIANCE") && entry.getValue().contains("TCS"))
                result.add(entry.getKey());
        return result; // Total: O(n)
    }

    public static void main(String[] args) {
        List<Trade> trades = new ArrayList<>();
        String[] stocks = {"RELIANCE","TCS","INFY","HDFCBANK"};
        Random rand = new Random(42);
        for (int i=0; i<10000; i++)
            trades.add(new Trade("TRADER-"+(rand.nextInt(200)), stocks[rand.nextInt(stocks.length)]));

        long s1=System.currentTimeMillis();
        List<String> slow = slowFind(trades);
        long t1=System.currentTimeMillis()-s1;

        long s2=System.currentTimeMillis();
        List<String> fast = fastFind(trades);
        long t2=System.currentTimeMillis()-s2;

        Collections.sort(slow); Collections.sort(fast);
        System.out.println("Slow O(n³): " + t1 + "ms, found " + slow.size() + " traders");
        System.out.println("Fast O(n):  " + t2 + "ms, found " + fast.size() + " traders");
        System.out.println("Same result: " + slow.equals(fast));
    }
}

