import java.util.*;
public class MergeSort {
    static int comparisons = 0;

    static void mergeSort(int[] arr, int l, int r) {
        if (l >= r) return;
        int mid = l + (r - l) / 2; // avoid integer overflow
        mergeSort(arr, l, mid);
        mergeSort(arr, mid + 1, r);
        merge(arr, l, mid, r);
    }

    static void merge(int[] arr, int l, int mid, int r) {
        int[] left = Arrays.copyOfRange(arr, l, mid + 1);
        int[] right = Arrays.copyOfRange(arr, mid + 1, r + 1);
        int i = 0, j = 0, k = l;
        while (i < left.length && j < right.length) {
            comparisons++;
            if (left[i] <= right[j]) arr[k++] = left[i++];
            else arr[k++] = right[j++];
        }
        while (i < left.length) arr[k++] = left[i++];
        while (j < right.length) arr[k++] = right[j++];
    }

    public static void main(String[] args) {
        int[] sizes = {8, 64, 1024, 16384};
        System.out.printf("%-10s %-15s %-20s %-15s%n",
            "n", "comparisons", "n*log2(n)", "ratio");
        System.out.println("-".repeat(60));

        for (int n : sizes) {
            int[] arr = new int[n];
            Random rand = new Random(42);
            for (int i = 0; i < n; i++) arr[i] = rand.nextInt(1000);

            comparisons = 0;
            mergeSort(arr, 0, arr.length - 1);

            double nlogn = n * (Math.log(n) / Math.log(2));
            double ratio = comparisons / nlogn;
            System.out.printf("%-10d %-15d %-20.0f %-15.2f%n", n, comparisons, nlogn, ratio);

            // Verify sorted:
            for (int i = 0; i < arr.length - 1; i++)
                assert arr[i] <= arr[i+1] : "Not sorted at " + i;
        }
        System.out.println();
        System.out.println("Ratio ≈ 0.5–1.0: confirms O(n log n) — comparisons proportional to n×log(n)");
    }
}

