public class StringComplexity {
    // O(n²): string concatenation creates a NEW string each time
    // At step i: copy i characters + add new trade → O(i) per step
    // Total: 0+1+2+...+(n-1) = n(n-1)/2 = O(n²) character copies
    static String slowConcat(String[] trades) {
        String result = "";
        for (String trade : trades) {
            result += trade + ","; // creates new String object each time!
        }
        return result;
    }

    // O(n): StringBuilder appends in-place (amortized O(1) per append)
    static String fastConcat(String[] trades) {
        StringBuilder sb = new StringBuilder();
        for (String trade : trades) {
            sb.append(trade).append(","); // O(1) amortized
        }
        return sb.toString(); // one final string copy: O(total length)
    }

    public static void main(String[] args) {
        int n = 10_000;
        String[] trades = new String[n];
        for (int i = 0; i < n; i++) trades[i] = "TRADE" + i;

        long s1 = System.currentTimeMillis();
        slowConcat(trades);
        long t1 = System.currentTimeMillis() - s1;

        long s2 = System.currentTimeMillis();
        fastConcat(trades);
        long t2 = System.currentTimeMillis() - s2;

        System.out.println("String concat O(n²): " + t1 + "ms");
        System.out.println("StringBuilder O(n):  " + t2 + "ms");
        System.out.println();
        System.out.println("WHY String concat is O(n²):");
        System.out.println("  Java Strings are IMMUTABLE.");
        System.out.println("  result += trade creates a brand new String object.");
        System.out.println("  At step i: copies the entire result (i chars) + new trade.");
        System.out.println("  Total copies: 0+1+2+...+(n-1) = n²/2 = O(n²)");
        System.out.println();
        System.out.println("StringBuilder: mutable internal char[], append is O(1) amortized.");
    }
}

