import java.util.*;
public class GroupAnagrams {

    // O(n² × m): compare each pair — are they anagrams?
    static List<List<String>> naive(String[] words) {
        boolean[] grouped = new boolean[words.length];
        List<List<String>> result = new ArrayList<>();
        for (int i = 0; i < words.length; i++) {
            if (grouped[i]) continue;
            List<String> group = new ArrayList<>();
            group.add(words[i]);
            for (int j = i+1; j < words.length; j++) {
                if (!grouped[j] && isAnagram(words[i], words[j])) {
                    group.add(words[j]); grouped[j] = true;
                }
            }
            result.add(group);
        }
        return result;
    }
    static boolean isAnagram(String a, String b) {
        char[] ca=a.toCharArray(), cb=b.toCharArray();
        Arrays.sort(ca); Arrays.sort(cb);
        return Arrays.equals(ca,cb); // O(m log m) per call
    }

    // O(n × m log m): sort each word → use as HashMap key
    static List<List<String>> sortedKey(String[] words) {
        Map<String, List<String>> map = new HashMap<>();
        for (String w : words) {
            char[] chars = w.toCharArray();
            Arrays.sort(chars); // O(m log m) — sort the word's chars
            String key = new String(chars);
            map.computeIfAbsent(key, k -> new ArrayList<>()).add(w);
        }
        return new ArrayList<>(map.values()); // O(n × m log m) total
    }

    // O(n × m): frequency array as key, no sorting needed
    static List<List<String>> freqKey(String[] words) {
        Map<String, List<String>> map = new HashMap<>();
        for (String w : words) {
            int[] freq = new int[26]; // count each letter
            for (char c : w.toCharArray()) freq[c - 'a']++; // O(m)
            map.computeIfAbsent(Arrays.toString(freq), k -> new ArrayList<>()).add(w);
        }
        return new ArrayList<>(map.values()); // O(n × m) total
    }

    public static void main(String[] args) {
        String[] words = {"eat","tea","tan","ate","nat","bat"};
        System.out.println("Input: " + Arrays.toString(words));
        System.out.println("Naive O(n²×m):       " + naive(words));
        System.out.println("SortedKey O(n×m logm): " + sortedKey(words));
        System.out.println("FreqKey O(n×m):       " + freqKey(words));
        System.out.println();
        System.out.println("All have same groups (possibly different order): "
            + (sortedKey(words).size() == freqKey(words).size()));
        System.out.println();
        System.out.println("Interview: start with sortedKey O(n×m log m), mention freqKey O(n×m) as optimal");
    }
}

