import java.util.*;
public class TreeTraversal {
    static class Node { int val; Node left, right;
        Node(int v){val=v;} Node(int v,Node l,Node r){val=v;left=l;right=r;}
    }

    // O(n): visit every node exactly once
    static long dfsSum(Node root) {
        if (root == null) return 0;
        return root.val + dfsSum(root.left) + dfsSum(root.right);
        // Recurrence: T(n) = T(left) + T(right) + O(1)
        // For balanced tree: T(n) = 2T(n/2) + O(1) → O(n)
        // Unbalanced: T(n) = T(n-1) + O(1) → still O(n)
    }

    // O(n): BFS processes each node once
    static long bfsSum(Node root) {
        if (root == null) return 0;
        long sum = 0;
        Queue<Node> queue = new LinkedList<>();
        queue.offer(root);
        while (!queue.isEmpty()) {
            Node node = queue.poll();
            sum += node.val;
            if (node.left != null) queue.offer(node.left);
            if (node.right != null) queue.offer(node.right);
        }
        return sum;
    }

    // Build balanced BST from sorted array
    static Node buildTree(int[] vals, int l, int r) {
        if (l > r) return null;
        int mid = l + (r - l) / 2;
        return new Node(vals[mid], buildTree(vals, l, mid-1), buildTree(vals, mid+1, r));
    }

    public static void main(String[] args) {
        int n = 1000;
        int[] vals = new int[n];
        long expectedSum = 0;
        for (int i = 0; i < n; i++) { vals[i] = i+1; expectedSum += i+1; }
        Node root = buildTree(vals, 0, n-1);

        long dfs = dfsSum(root);
        long bfs = bfsSum(root);

        System.out.println("n = " + n + " nodes");
        System.out.println("DFS sum: " + dfs);
        System.out.println("BFS sum: " + bfs);
        System.out.println("Both correct: " + (dfs == expectedSum && bfs == expectedSum));
        System.out.println();
        System.out.println("Complexity: BOTH are O(n)");
        System.out.println("  DFS: visits each node once via recursion → O(n) time, O(h) stack space");
        System.out.println("  BFS: processes each node once via queue → O(n) time, O(w) queue space");
        System.out.println("  h = tree height (O(log n) balanced, O(n) skewed)");
        System.out.println("  w = max width (O(n) for complete tree)");
        System.out.println("  For balanced tree: DFS space O(log n) < BFS space O(n) → DFS preferred");
    }
}

