import java.util.*;
public class ComplexitySynthesis {
    record Pair(int a, int b) {}

    // O(n²): check every pair
    static Set<Pair> bruteForce(int[] t, int target) {
        Set<Pair> result = new TreeSet<>(Comparator.comparingInt(Pair::a).thenComparingInt(Pair::b));
        for (int i=0; i<t.length; i++)
            for (int j=i+1; j<t.length; j++)
                if (t[i]+t[j]==target)
                    result.add(new Pair(Math.min(t[i],t[j]),Math.max(t[i],t[j])));
        return result;
    }

    // O(n log n): sort + two pointers
    static Set<Pair> sortedTwoPointers(int[] t, int target) {
        int[] s=t.clone(); Arrays.sort(s);
        Set<Pair> result = new HashSet<>();
        int lo=0, hi=s.length-1;
        while(lo<hi){
            int sum=s[lo]+s[hi];
            if(sum==target){result.add(new Pair(s[lo],s[hi]));lo++;hi--;}
            else if(sum<target) lo++;
            else hi--;
        }
        return result;
    }

    // O(n): HashMap
    static Set<Pair> hashMapApproach(int[] t, int target) {
        Set<Pair> result = new HashSet<>();
        Set<Integer> seen = new HashSet<>();
        for(int x:t){
            int comp=target-x;
            if(seen.contains(comp)) result.add(new Pair(Math.min(x,comp),Math.max(x,comp)));
            seen.add(x);
        }
        return result;
    }

    public static void main(String[] args) {
        int[] trades={2,7,4,3,11,9,1,6};
        int target=10;
        var bf=bruteForce(trades,target);
        var tp=sortedTwoPointers(trades,target);
        var hm=hashMapApproach(trades,target);

        System.out.println("Input: " + Arrays.toString(trades) + ", target=" + target);
        System.out.println("Brute Force O(n²):        " + bf);
        System.out.println("Two Pointers O(n log n):  " + tp);
        System.out.println("HashMap O(n):             " + hm);
        System.out.println();
        System.out.println("All find same unique pairs: " + (bf.size()==tp.size() && tp.size()==hm.size()));
        System.out.println();
        System.out.println("Complexity summary:");
        System.out.println("  O(n²): " + (trades.length*(long)trades.length) + " ops at n=" + trades.length);
        System.out.println("  O(n log n): " + (int)(trades.length*Math.log(trades.length)/Math.log(2)) + " ops");
        System.out.println("  O(n): " + trades.length + " ops");
        System.out.println("  Best choice: HashMap O(n) — linear time, O(n) space");
    }
}
